sql:
SELECT book_id, title, rating
FROM books
WHERE rating > (SELECT AVG(rating) FROM books);

SELECT users.user_id, books.book_id
FROM users, books
WHERE users.user_id = books.book_id;

external_knowledge:
- 'administrative guides' refers to users with the role 'admin';
- 'ventured through the checkout gate' refers to having a cart with the status 'checked out';
- 'literary gardens' refer to publishers;
- 'literary harvest' refers to the books published by those publishers;
- 'richness of their literary harvest' refers to the count of books published by each publisher;
- arranged from the most prolific to the less means sorted in descending order based on the count of books published.

sql:
SELECT COUNT(DISTINCT user_id) AS user_count
FROM carts
WHERE discount_code = 'DISC10';

SELECT cart_id, status, total_amount, discount_code
FROM carts
WHERE user_id = 1;

external_knowledge:
- 'literary stars' refers to books with ratings greater than 4.0; 
- 'glow brighter than 4.0' metaphorically refers to a rating greater than 4.0; 
- 'constellations of authors' symbolizes the collective authors of each book.
